// src/pages/dashboard/AdminDashboard.js
import React from "react";
import Layout from "../../components/layout/Layout";
import Navbar from "../../components/Navbar";
import Sidebar from "../../components/Sidebar";
import { Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);

function AdminDashboard() {
  // Example chart data
  const chartData = {
    labels: ["Jan", "Feb", "Mar", "Apr", "May", "Jun"],
    datasets: [
      {
        label: "New Users",
        data: [120, 190, 300, 250, 400, 350],
        backgroundColor: "#4f46e5",
      },
      {
        label: "Courses Published",
        data: [20, 25, 18, 30, 28, 40],
        backgroundColor: "#10b981",
      },
    ],
  };

  const chartOptions = {
    responsive: true,
    plugins: {
      legend: { position: "top" },
      title: { display: true, text: "Monthly Overview" },
    },
  };

  return (
    <Layout pageTitle="Admin Dashboard - NexaLearn LMS">
      <Navbar />
      <div className="d-flex" style={{ minHeight: "80vh" }}>
        <Sidebar />
        <div className="flex-grow-1 p-4">
          <h1 style={{ color: "#4f46e5", fontWeight: "700", marginBottom: "25px" }}>
            Admin Dashboard
          </h1>

          <div className="row g-4 mb-4">
            <div className="col-md-4">
              <div className="card shadow-sm p-3" style={{ borderLeft: "5px solid #4f46e5", borderRadius: "10px" }}>
                <h5 className="card-title text-secondary">Total Users</h5>
                <p className="display-5 fw-bold">1,234</p>
                <p className="text-success">+5.4% since last month</p>
              </div>
            </div>

            <div className="col-md-4">
              <div className="card shadow-sm p-3" style={{ borderLeft: "5px solid #10b981", borderRadius: "10px" }}>
                <h5 className="card-title text-secondary">Courses Published</h5>
                <p className="display-5 fw-bold">56</p>
                <p className="text-success">+2 new courses</p>
              </div>
            </div>

            <div className="col-md-4">
              <div className="card shadow-sm p-3" style={{ borderLeft: "5px solid #ef4444", borderRadius: "10px" }}>
                <h5 className="card-title text-secondary">Pending Approvals</h5>
                <p className="display-5 fw-bold">7</p>
                <p className="text-warning">Needs your attention</p>
              </div>
            </div>
          </div>

          {/* Chart Section */}
          <div className="card shadow-sm p-4 mb-4" style={{ borderRadius: "12px" }}>
            <h5 style={{ marginBottom: "20px", fontWeight: "600" }}>Monthly Activity</h5>
            <Bar data={chartData} options={chartOptions} />
          </div>

          {/* Recent Activity */}
          <h3 className="mb-3" style={{ color: "#374151" }}>
            Recent Activity
          </h3>
          <ul className="list-group shadow-sm">
            <li className="list-group-item d-flex justify-content-between align-items-center">
              New course "React Basics" submitted by instructor John Doe
              <span className="badge bg-primary rounded-pill">2h ago</span>
            </li>
            <li className="list-group-item d-flex justify-content-between align-items-center">
              User Jane Smith registered
              <span className="badge bg-primary rounded-pill">5h ago</span>
            </li>
            <li className="list-group-item d-flex justify-content-between align-items-center">
              Course "Advanced Python" approved
              <span className="badge bg-primary rounded-pill">1d ago</span>
            </li>
          </ul>
        </div>
      </div>
    </Layout>
  );
}

export default AdminDashboard;
